function exportGroups(){
  var sel = store.groups.filter(function(g){ return g.enabled; });
  if(!sel.length){ ctx.toast && ctx.toast('没有已勾选启用的图组可导出'); return; }
  var tasks = [];
  sel.forEach(function(g){ (g.imgs||[]).forEach(function(it){ if(it.media) tasks.push(it); }); });
  var pending = tasks.length;
  function finish(){
    function clean(g){ return { name:g.name, enabled:g.enabled, imgs:(g.imgs||[]).map(function(it){
      return { enabled:it.enabled, type:it.type, src:(it.__exp||it.src||''), name:it.name, scene:it.scene, expr:it.expr, action:it.action }; }) }; }
    var data = JSON.stringify({ vnmWallpaperExport:true, groups: sel.map(clean) }, null, 2);
    tasks.forEach(function(it){ delete it.__exp; });
    try{
      var blob = new (TOP.Blob||Blob)([data], { type:'application/json' });
      var url = (TOP.URL||URL).createObjectURL(blob);
      var a = TOPDOC.createElement('a'); a.href=url; a.download='wallpaper-groups-'+Date.now()+'.json';
      TOPDOC.body.appendChild(a); a.click(); a.remove();
      TOP.setTimeout(function(){ try{ (TOP.URL||URL).revokeObjectURL(url); }catch(e){} }, 1500);
      ctx.toast && ctx.toast('已导出 '+sel.length+' 个图组');
    }catch(e){ ctx.toast && ctx.toast('导出失败'); }
  }
  if(!pending){ finish(); return; }
  ctx.toast && ctx.toast('正在打包媒体…');
  tasks.forEach(function(it){
    _wpGet(TOP, it.media, function(blob){
      if(blob){ var fr=new (TOP.FileReader||FileReader)(); fr.onload=function(){ it.__exp=fr.result; if(--pending===0) finish(); }; fr.onerror=function(){ if(--pending===0) finish(); }; fr.readAsDataURL(blob); }
      else { if(--pending===0) finish(); }
    });
  });
}
expBtn.onclick = exportGroups;

function importGroups(){
  var fin = DOC.createElement('input'); fin.type='file'; fin.accept='.json,application/json'; fin.style.display='none';
  fin.onchange = function(){
    var f = fin.files && fin.files[0]; if(!f) return;
    var fr = new (TOP.FileReader||FileReader)();
    fr.onload = function(){
      try{
        var o = JSON.parse(fr.result);
        var gs = o.groups || (Array.isArray(o) ? o : [o]);
        gs.forEach(function(g){
          g.id = 'g'+Date.now()+Math.floor(Math.random()*1e4);
          if(g.enabled===undefined) g.enabled = true;
          g._open = false; g.imgs = g.imgs || [];
          g.imgs.forEach(function(it){
            if(it.src && /^data:/i.test(it.src)){
              try{ var blob=_wpDataToBlob(it.src); var mid='wp'+Date.now()+Math.floor(Math.random()*1e6);
                _wpPut(TOP, mid, blob, function(){}); it.media=mid; it.src=''; it.resolved=''; }catch(e){}
            }
          });
        });
        persist(); render();
        ctx.toast && ctx.toast('已导入 '+gs.length+' 个图组');
      }catch(e){ ctx.toast && ctx.toast('导入失败：文件格式不正确'); }
    };
    fr.readAsText(f);
  };
  TOPDOC.body.appendChild(fin); fin.click();
  TOP.setTimeout(function(){ if(fin.parentNode) fin.parentNode.removeChild(fin); }, 3000);
}
impBtn.onclick = importGroups;

