  /* 状态查询函数：用户在 F12 控制台输入 __vnm3D() 查看 */
  TOP.__vnm3D=function(){var s=TOP.__vnmWPDepth;if(!s){console.log('[VNM-3D] 引擎未运行(深度开关关闭?)');return '引擎未运行';}console.log('[VNM-3D] 状态:',JSON.parse(JSON.stringify(s.stat)),'帧数',s.frames,'当前图',s.curUrl?'有':'无');return s.stat;};
  _wpDLog('提示：F12 控制台输入 __vnm3D() 可随时查看状态');
  st._mm=function(e){var w=TOP.innerWidth||1920,h=TOP.innerHeight||1080;st.mx=((e.clientX/w)-0.5)*2;st.my=((e.clientY/h)-0.5)*2;};
  st._go=function(e){st.mx=Math.max(-1,Math.min(1,(e.gamma||0)/35));st.my=Math.max(-1,Math.min(1,((e.beta||45)-45)/35));};
  TOP.document.addEventListener('mousemove',st._mm,{passive:true});
  if(typeof TOP.DeviceOrientationEvent!=='undefined') TOP.addEventListener('deviceorientation',st._go,{passive:true});
  function _parseUrl(s){var m=(s||'').match(/url\(["']?(.*?)["']?\)/i);return m?m[1]:null;}
  function pickBase(){
    var bg=_wpFindBg(TOP);if(!bg)return null;var ov=bg.parentNode;if(!ov)return null;
    var u=_parseUrl(bg.style.backgroundImage);
    if(u)return {ov:ov,url:u,src:'智绘姬'};
    var wl=ov.querySelector('#vnm-wallpaper');
    if(wl){var v=wl.querySelector('#vnm-wallpaper-vid');var isVid=v&&v.style.display!=='none';
      if(!isVid){var wu=_parseUrl(wl.style.backgroundImage);var op=parseFloat(wl.style.opacity||'0');if(wu&&op>0.01)return {ov:ov,url:wu,src:'预制图'};}}
    return {ov:ov,url:null,src:null};
  }
  function tick(){
    st.raf=TOP.requestAnimationFrame(tick);
    var pb=pickBase();
    if(!pb){if(st._loggedBase!=='nobg'){st._loggedBase='nobg';_wpDLog('未找到看图器底图元素 #vnm-bg（需打开 VN 看图器）');}_wpDStat(TOP,{base:'无#vnm-bg'});return;}
    var ov=pb.ov,url=pb.url;
    var cv=st.canvas;
    if(!cv||!cv.isConnected){
      cv=TOP.document.createElement('canvas');cv.id='vnm-wp-depth';
      cv.style.cssText='position:absolute;inset:0;width:100%;height:100%;pointer-events:none;opacity:0;transition:opacity .3s;display:block;z-index:0;';
      var cl=ov.querySelector('#vnm-click-layer');
      if(cl)ov.insertBefore(cv,cl);else ov.appendChild(cv);
      st.canvas=cv;st.gl=_wpDepthGL(TOP,cv);
      st.stat.webgl2=st.gl?'可用':'不可用';
      _wpDLog('创建深度画布 #vnm-wp-depth，WebGL2:',st.stat.webgl2);
    }
    if(!st.gl)return;
    var srcLabel=(pb.src||'无底图');
    if(st._loggedBase!==srcLabel){st._loggedBase=srcLabel;_wpDLog('当前底图来源:',srcLabel,url?('('+(/^data:/.test(url)?'data图':'链接')+')'):'(无图)');}
    _wpDStat(TOP,{base:srcLabel+(url?'·有图':'·无图')});
    if(!url){cv.style.opacity='0';return;}
    if(url!==st.curUrl&&url!==st.loadingUrl){
      st.loadingUrl=url;st.have=false;_wpDLog('载入底图…');_wpDStat(TOP,{img:'加载中'});
      (function(target){var img=new TOP.Image();img.crossOrigin='anonymous';
        img.onload=function(){if(st.loadingUrl!==target)return;st.iw=img.naturalWidth||img.width;st.ih=img.naturalHeight||img.height;st.gl.setColor(img);st.gl.setDepth(st.neutral);st.have=true;st.curUrl=target;_wpDLog('底图已上 GL，先平面显示',st.iw+'x'+st.ih);_wpDStat(TOP,{img:'已显示 '+st.iw+'x'+st.ih});
          _wpDepthGetMap(TOP,target,function(dimg){if(st.curUrl!==target)return;if(dimg){st.gl.setDepth(dimg);_wpDLog('深度图已叠加，开始 3D 晃动');}});};
        img.onerror=function(){if(st.loadingUrl===target){st.loadingUrl=null;_wpDLog('底图加载失败');_wpDStat(TOP,{img:'加载失败'});}};
        img.src=target;})(url);
    }
    if(!st.have){return;}
    var dpr=Math.min(TOP.devicePixelRatio||1,1.5);
    var pw=Math.round(cv.clientWidth*dpr),ph=Math.round(cv.clientHeight*dpr);
    if(pw>0&&ph>0&&(cv.width!==pw||cv.height!==ph)){cv.width=pw;cv.height=ph;}
    var boxW=cv.clientWidth||1,boxH=cv.clientHeight||1;
    var scale=Math.max(boxW/st.iw,boxH/st.ih),drawW=st.iw*scale,drawH=st.ih*scale;
    var usx=boxW/drawW,usy=boxH/drawH,uox=(1-usx)/2,uoy=(1-usy)/2;
    var amp=Math.max(0,(st.cfg.depthIntensity||60))/100*0.13;
    var focus=Math.min(1,Math.max(0,(st.cfg.depthFocus!=null?st.cfg.depthFocus:50)/100));
    var invert=st.cfg.depthInvert?1:0;
    st.vx=st.vx*0.82+(st.mx-st.cx)*0.08;st.vy=st.vy*0.82+(st.my-st.cy)*0.08;st.cx+=st.vx;st.cy+=st.vy;
    st.gl.draw({cx:st.cx,cy:-st.cy,amp:amp,focus:focus,invert:invert,over:1.0+amp+0.04,usx:usx,usy:usy,uox:uox,uoy:uoy});
    cv.style.opacity='1';st.frames++;
    if(!st._loggedFrame){st._loggedFrame=true;_wpDLog('已开始渲染深度画面（canvas',cv.clientWidth+'x'+cv.clientHeight+'，像素',cv.width+'x'+cv.height+'）');if(cv.clientWidth<2||cv.clientHeight<2)_wpDLog('⚠ 画布尺寸为0，可能被 display:none 或父元素未展开');}
  }
  st.raf=TOP.requestAnimationFrame(tick);
}
function _wpDepthTeardown(TOP){
  var st=TOP.__vnmWPDepth;if(!st)return;
  if(st.raf)TOP.cancelAnimationFrame(st.raf);
  if(st._mm)TOP.document.removeEventListener('mousemove',st._mm);
  if(st._go)TOP.removeEventListener('deviceorientation',st._go);
  try{if(st.canvas&&st.canvas.parentNode)st.canvas.parentNode.removeChild(st.canvas);}catch(e){}
  TOP.__vnmWPDepth=null;
  _wpDLog('深度引擎已停止');
}

function _wpParallaxInstall(TOP,cfg){
  _wpParallaxTeardown(TOP);
  if(!cfg||!cfg.enabled||!cfg.spatial) return;
  var maxD=Math.max(1,cfg.spatialIntensity||60)*0.6;
  var par=TOP.__vnmWPPar={mx:0,my:0,cx:0,cy:0,vx:0,vy:0,raf:0};
  function onMouse(e){
    var w=TOP.innerWidth||1920,h=TOP.innerHeight||1080;
    par.mx=((e.clientX/w)-0.5)*2;
    par.my=((e.clientY/h)-0.5)*2;
  }
  function onGyro(e){
    par.mx=Math.max(-1,Math.min(1,(e.gamma||0)/35));
    par.my=Math.max(-1,Math.min(1,((e.beta||45)-45)/35));
  }
  TOP.document.addEventListener('mousemove',onMouse,{passive:true});
  par._mm=onMouse;
  if(typeof TOP.DeviceOrientationEvent!=='undefined'){
    TOP.addEventListener('deviceorientation',onGyro,{passive:true});
    par._go=onGyro;
  }
  var stiff=0.08,damp=0.82;
  function tick(){
    par.raf=TOP.requestAnimationFrame(tick);
    var tx=par.mx*maxD,ty=par.my*maxD;
    par.vx=par.vx*damp+(tx-par.cx)*stiff;
    par.vy=par.vy*damp+(ty-par.cy)*stiff;
    par.cx+=par.vx;par.cy+=par.vy;
    var bg=_wpFindBg(TOP);if(!bg)return;
    var ov=bg.parentNode;if(!ov)return;
    var layer=ov.querySelector('#vnm-wallpaper');if(!layer)return;
    layer.style.transform='scale(1.1) translate('+(-par.cx).toFixed(2)+'px,'+(-par.cy).toFixed(2)+'px)';
    layer.style.filter='blur(0.8px)';
    var fgL=ov.querySelector('#vnm-wallpaper-fg');
    if(fgL&&parseFloat(fgL.style.opacity)>0){
      fgL.style.transform='scale(1.02) translate('+(-par.cx*0.15).toFixed(2)+'px,'+(-par.cy*0.15).toFixed(2)+'px)';
      fgL.style.filter='';
    }
  }
  par.raf=TOP.requestAnimationFrame(tick);
}
function _wpParallaxTeardown(TOP){
  var par=TOP.__vnmWPPar;if(!par)return;
  if(par.raf)TOP.cancelAnimationFrame(par.raf);
  if(par._mm)TOP.document.removeEventListener('mousemove',par._mm);
  if(par._go)TOP.removeEventListener('deviceorientation',par._go);
  TOP.__vnmWPPar=null;
  try{
    var bg=_wpFindBg(TOP);if(!bg)return;
    var ov=bg.parentNode;if(!ov)return;
    var ly=ov.querySelector('#vnm-wallpaper');
    if(ly){ly.style.transform='';ly.style.filter='';}
    var fl=ov.querySelector('#vnm-wallpaper-fg');
    if(fl){fl.style.transform='';fl.style.filter='';}
  }catch(e){}
}

